import React, { useEffect, useState, useCallback, useRef } from 'react';
import { View, Text, TextInput, Button, ActivityIndicator, StyleSheet, Alert } from 'react-native';
import * as SecureStore from 'expo-secure-store';

// Replace with your API base URL
const API_BASE = 'https://example.com';

const ACCESS_TOKEN_KEY = 'access_token';
const REFRESH_TOKEN_KEY = 'refresh_token';
const TOKEN_EXPIRES_AT_KEY = 'token_expires_at'; // epoch ms

type Tokens = { accessToken: string; refreshToken?: string; expiresAt?: number };

async function saveTokens(tokens: Tokens) {
  await SecureStore.setItemAsync(ACCESS_TOKEN_KEY, tokens.accessToken);
  if (tokens.refreshToken) await SecureStore.setItemAsync(REFRESH_TOKEN_KEY, tokens.refreshToken);
  if (tokens.expiresAt) await SecureStore.setItemAsync(TOKEN_EXPIRES_AT_KEY, tokens.expiresAt.toString());
}

async function clearTokens() {
  await SecureStore.deleteItemAsync(ACCESS_TOKEN_KEY);
  await SecureStore.deleteItemAsync(REFRESH_TOKEN_KEY);
  await SecureStore.deleteItemAsync(TOKEN_EXPIRES_AT_KEY);
}

async function readTokens(): Promise<Tokens | null> {
  const accessToken = await SecureStore.getItemAsync(ACCESS_TOKEN_KEY);
  if (!accessToken) return null;
  const refreshToken = await SecureStore.getItemAsync(REFRESH_TOKEN_KEY);
  const expiresAtStr = await SecureStore.getItemAsync(TOKEN_EXPIRES_AT_KEY);
  const expiresAt = expiresAtStr ? Number(expiresAtStr) : undefined;
  return { accessToken, refreshToken: refreshToken ?? undefined, expiresAt };
}

// Wrapper around fetch that attaches Authorization header and refreshes token on 401
function useAuthFetch(onSignOut: () => void) {
  const refreshingRef = useRef<Promise<boolean> | null>(null);

  const refreshTokens = useCallback(async (): Promise<boolean> => {
    // Ensure only one refresh happens concurrently
    if (refreshingRef.current) return refreshingRef.current;
    const p = (async () => {
      const refreshToken = await SecureStore.getItemAsync(REFRESH_TOKEN_KEY);
      if (!refreshToken) return false;
      try {
        const res = await fetch(`${API_BASE}/api/refresh`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ refreshToken }),
        });
        if (!res.ok) return false;
        const json = await res.json();
        // Expect { accessToken, refreshToken?, expiresIn }
        const { accessToken, refreshToken: newRefresh, expiresIn } = json;
        const expiresAt = expiresIn ? Date.now() + expiresIn * 1000 : undefined;
        await saveTokens({ accessToken, refreshToken: newRefresh ?? refreshToken, expiresAt });
        return true;
      } catch (e) {
        return false;
      }
    })();
    refreshingRef.current = p;
    const result = await p;
    refreshingRef.current = null;
    return result;
  }, []);

  const authFetch = useCallback(
    async (input: RequestInfo, init?: RequestInit, retry = true): Promise<Response> => {
      const tokens = await readTokens();
      const headers = new Headers(init?.headers || {});
      if (tokens?.accessToken) headers.set('Authorization', `Bearer ${tokens.accessToken}`);
      const res = await fetch(typeof input === 'string' ? input : input, { ...init, headers });
      if (res.status === 401 && retry) {
        const ok = await refreshTokens();
        if (ok) {
          return authFetch(input, init, false); // retry once after refresh
        }
        // refresh failed -> sign out
        await clearTokens();
        onSignOut();
      }
      return res;
    },
    [onSignOut, refreshTokens]
  );

  return { authFetch, refreshTokens };
}

export default function App() {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(true);
  const [authenticating, setAuthenticating] = useState(false);
  const [user, setUser] = useState<any | null>(null);

  const signOut = useCallback(() => {
    setUser(null);
    clearTokens();
  }, []);

  const { authFetch, refreshTokens } = useAuthFetch(() => signOut());

  // Validate on mount: if tokens present, fetch /api/me
  useEffect(() => {
    let mounted = true;
    (async () => {
      setLoading(true);
      try {
        const tokens = await readTokens();
        if (!tokens) {
          setUser(null);
          setLoading(false);
          return;
        }
        // If token is close to expiry, refresh now (e.g., within 60s)
        if (tokens.expiresAt && Date.now() > tokens.expiresAt - 60_000) {
          const ok = await refreshTokens();
          if (!ok) {
            setUser(null);
            setLoading(false);
            return;
          }
        }
        const res = await authFetch(`${API_BASE}/api/me`);
        if (res.ok) {
          const json = await res.json();
          if (mounted) setUser(json);
        } else {
          if (mounted) setUser(null);
        }
      } catch (e) {
        if (mounted) setUser(null);
      } finally {
        if (mounted) setLoading(false);
      }
    })();
    return () => { mounted = false; };
  }, [authFetch, refreshTokens]);

  // Automatic background refresh: try to refresh when token is near expiry every 30s
  useEffect(() => {
    let interval: number | undefined;
    let mounted = true;
    (async () => {
      const tokens = await readTokens();
      if (!tokens || !tokens.expiresAt) return;
      if (!mounted) return;
      interval = setInterval(async () => {
        const t = await readTokens();
        if (!t || !t.expiresAt) return;
        const now = Date.now();
        // refresh if within 60s of expiry
        if (t.expiresAt - now < 60_000) {
          await refreshTokens();
        }
      }, 30_000) as unknown as number;
    })();
    return () => { mounted = false; if (interval) clearInterval(interval); };
  }, [refreshTokens]);

  const handleLogin = async () => {
    setAuthenticating(true);
    try {
      const res = await fetch(`${API_BASE}/api/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username, password }),
      });
      if (!res.ok) {
        const text = await res.text();
        Alert.alert('Login failed', text || res.statusText);
        setAuthenticating(false);
        return;
      }
      const json = await res.json();
      // Expect { accessToken, refreshToken?, expiresIn }
      const { accessToken, refreshToken, expiresIn } = json;
      const expiresAt = expiresIn ? Date.now() + expiresIn * 1000 : undefined;
      await saveTokens({ accessToken, refreshToken, expiresAt });
      // Fetch user profile
      const profileRes = await authFetch(`${API_BASE}/api/me`);
      if (profileRes.ok) setUser(await profileRes.json());
    } catch (e) {
      Alert.alert('Error', String(e));
    } finally {
      setAuthenticating(false);
    }
  };

  const handleProtectedAction = async () => {
    try {
      const res = await authFetch(`${API_BASE}/api/protected`, { method: 'GET' });
      if (res.ok) {
        const j = await res.json();
        Alert.alert('Protected response', JSON.stringify(j));
      } else {
        Alert.alert('Request failed', `Status ${res.status}`);
      }
    } catch (e) {
      Alert.alert('Network error', String(e));
    }
  };

  if (loading) {
    return (
      <View style={styles.center}>
        <ActivityIndicator size="large" />
        <Text style={{ marginTop: 12 }}>Checking authentication...</Text>
      </View>
    );
  }

  if (!user) {
    return (
      <View style={styles.container}>
        <Text style={styles.title}>Sign in</Text>
        <TextInput
          placeholder="Username"
          value={username}
          onChangeText={setUsername}
          style={styles.input}
          autoCapitalize="none"
        />
        <TextInput
          placeholder="Password"
          value={password}
          onChangeText={setPassword}
          style={styles.input}
          secureTextEntry
        />
        <Button title={authenticating ? 'Signing in...' : 'Sign in'} onPress={handleLogin} disabled={authenticating} />
        <Text style={styles.hint}>
          This demo stores tokens in Expo SecureStore and attaches Bearer tokens to requests. Server endpoints: /api/login, /api/refresh, /api/me.
        </Text>
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Welcome, {user.name ?? user.username ?? 'user'}!</Text>
      <Text style={{ marginBottom: 12 }}>You are authenticated.</Text>
      <Button title="Call protected API" onPress={handleProtectedAction} />
      <View style={{ height: 12 }} />
      <Button title="Sign out" onPress={() => { signOut(); }} color="#c00" />
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, padding: 20, justifyContent: 'center' },
  center: { flex: 1, alignItems: 'center', justifyContent: 'center' },
  title: { fontSize: 22, fontWeight: '600', marginBottom: 12 },
  input: { borderWidth: 1, borderColor: '#ddd', padding: 10, marginBottom: 12, borderRadius: 6 },
  hint: { marginTop: 12, color: '#666', fontSize: 12 },
});

import React from 'react';
import { useSyncExternalStore } from 'react';
import { View, Text, Button, StyleSheet, SafeAreaView } from 'react-native';

// Simple counter store demonstrating useSyncExternalStore
type Subscriber = () => void;
const createCounterStore = () => {
  let count = 0;
  const subs = new Set<Subscriber>();
  let intervalId: number | null = null;

  const notify = () => subs.forEach((s) => s());

  return {
    subscribe: (cb: Subscriber) => {
      subs.add(cb);
      // return unsubscribe
      return () => subs.delete(cb);
    },
    getSnapshot: () => count,
    // optional server snapshot (used for SSR) — keep same shape
    getServerSnapshot: () => 0,
    // control helpers
    startAutoIncrement: () => {
      if (intervalId != null) return;
      intervalId = setInterval(() => {
        count += 1;
        notify();
      }, 1000) as unknown as number;
    },
    stopAutoIncrement: () => {
      if (intervalId != null) {
        clearInterval(intervalId as unknown as number);
        intervalId = null;
      }
    },
    increment: () => {
      count += 1;
      notify();
    },
    decrement: () => {
      count -= 1;
      notify();
    },
    reset: () => {
      count = 0;
      notify();
    },
  };
};

const counterStore = createCounterStore();

export default function App(): JSX.Element {
  // Subscribe to the external store using React 19 API
  const count = useSyncExternalStore(
    counterStore.subscribe,
    counterStore.getSnapshot,
    counterStore.getServerSnapshot
  );

  return (
    <SafeAreaView style={styles.safe}>
      <View style={styles.container}>
        <Text style={styles.title}>useSyncExternalStore Counter</Text>
        <Text style={styles.count}>{count}</Text>

        <View style={styles.row}>
          <Button title="-" onPress={counterStore.decrement} />
          <View style={styles.spacer} />
          <Button title="+" onPress={counterStore.increment} />
        </View>

        <View style={styles.row}>
          <Button title="Start Auto" onPress={counterStore.startAutoIncrement} />
          <View style={styles.spacer} />
          <Button title="Stop Auto" onPress={counterStore.stopAutoIncrement} />
        </View>

        <View style={styles.row}>
          <Button title="Reset" onPress={counterStore.reset} />
        </View>

        <Text style={styles.hint}>
          The UI updates synchronously with the external store using useSyncExternalStore.
        </Text>
      </View>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
