import React, { useEffect, useState } from "react";
import { StyleSheet, Text, View, Button, ActivityIndicator, Alert } from "react-native";
import Constants from "expo-constants";
import * as Updates from "expo-updates";

export default function App(): JSX.Element {
  const [runtimeVersion, setRuntimeVersion] = useState<string | null>(null);
  const [releaseChannel, setReleaseChannel] = useState<string | null>(null);
  const [checking, setChecking] = useState(false);
  const [updateAvailable, setUpdateAvailable] = useState<boolean | null>(null);

  useEffect(() => {
    // Read runtimeVersion from expo config, expo-updates, or manifest with safe fallbacks
    const rv =
      (Constants.expoConfig as any)?.runtimeVersion ??
      (Updates as any)?.runtimeVersion ??
      (Constants.manifest as any)?.runtimeVersion ??
      "unknown";
    setRuntimeVersion(String(rv));

    // releaseChannel is set in classic updates; EAS typically uses runtimeVersion, but manifest may still contain a channel
    const rc =
      (Constants.manifest as any)?.releaseChannel ??
      (Constants.expoConfig as any)?.releaseChannel ??
      process.env.EXPO_RELEASE_CHANNEL ??
      "default";
    setReleaseChannel(String(rc));
  }, []);

  async function checkForUpdate() {
    try {
      setChecking(true);
      const { isAvailable } = await Updates.checkForUpdateAsync();
      setUpdateAvailable(isAvailable);
      if (isAvailable) {
        // Fetches the update; applied on next restart (or call Reload if desired)
        await Updates.fetchUpdateAsync();
        Alert.alert("Update downloaded", "An update was downloaded and will be applied on restart.");
      } else {
        Alert.alert("No update", "The app is up to date.");
      }
    } catch (e) {
      Alert.alert("Update error", String(e));
    } finally {
      setChecking(false);
    }
  }

  return (
    <View style={styles.container}>
      <Text style={styles.title}>EAS Update Info</Text>
      <Text style={styles.label}>runtimeVersion: <Text style={styles.value}>{runtimeVersion}</Text></Text>
      <Text style={styles.label}>releaseChannel: <Text style={styles.value}>{releaseChannel}</Text></Text>

      <View style={{ height: 20 }} />
      <Button title="Check for update" onPress={checkForUpdate} disabled={checking} />
      {checking && <ActivityIndicator style={{ marginTop: 10 }} />}

      {updateAvailable === true && <Text style={styles.notice}>Update available and fetched</Text>}
      {updateAvailable === false && <Text style={styles.notice}>No update available</Text>}
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, alignItems: "center", justifyContent: "center", padding: 16 },
  title: { fontSize: 20, fontWeight: "600", marginBottom: 12 },
  label: { fontSize: 16, marginTop: 6 },
  value: { fontWeight: "700" },
  notice: { marginTop: 12, color: "#0a84ff" }
});
